export const API_BASE = "http://localhost:5000"; // backend URL

export const fetchAPI = async (url, options = {}) => {
  const res = await fetch(`${API_BASE}${url}`, {
    ...options,
    credentials: "include", // 🔥 cookies kosam important
    headers: {
      "Content-Type": "application/json",
      ...(options.headers || {}),
    },
  });

  return res.json();
};